INSERT INTO words (word, category_id, position, tag, zh, en, example_en, example_zh, synonyms) VALUES
  ('then', 'op', 81, 'OP', '然后；那时', 'at that time or next in order', 'First read the rule, then write an example.', '先读规则，然后写一个例句。', '[{"w":"still","def":"still: 相关的动作或关系词","vs":"与 then 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"still\" / \"then\" 的替换练习"},{"w":"there","def":"there: 可帮助扩展句型的基础词","vs":"与 then 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"there\" / \"then\" 的替换练习"},{"w":"together","def":"together: 同一组 Basic English 操作词","vs":"与 then 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"together\" / \"then\" 的替换练习"}]'),
  ('there', 'op', 82, 'OP', '那里；存在；用于引出', 'in or to that place, or used to show existence', 'There is a small light in the window.', '窗户里有一盏小灯。', '[{"w":"then","def":"then: 相关的动作或关系词","vs":"与 there 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"then\" / \"there\" 的替换练习"},{"w":"together","def":"together: 可帮助扩展句型的基础词","vs":"与 there 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"together\" / \"there\" 的替换练习"},{"w":"well","def":"well: 同一组 Basic English 操作词","vs":"与 there 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"well\" / \"there\" 的替换练习"}]'),
  ('together', 'op', 83, 'OP', '一起；共同', 'with one another or in one group', 'The family sat together at the table.', '一家人一起坐在桌边。', '[{"w":"there","def":"there: 相关的动作或关系词","vs":"与 together 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"there\" / \"together\" 的替换练习"},{"w":"well","def":"well: 可帮助扩展句型的基础词","vs":"与 together 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"well\" / \"together\" 的替换练习"},{"w":"almost","def":"almost: 同一组 Basic English 操作词","vs":"与 together 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"almost\" / \"together\" 的替换练习"}]'),
  ('well', 'op', 84, 'OP', '好；健康；充分地', 'in a good way or in good health', 'She can write Basic English well.', '她能很好地写基础英语。', '[{"w":"together","def":"together: 相关的动作或关系词","vs":"与 well 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"together\" / \"well\" 的替换练习"},{"w":"almost","def":"almost: 可帮助扩展句型的基础词","vs":"与 well 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"almost\" / \"well\" 的替换练习"},{"w":"enough","def":"enough: 同一组 Basic English 操作词","vs":"与 well 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"enough\" / \"well\" 的替换练习"}]'),
  ('almost', 'op', 85, 'OP', '几乎；差不多', 'very nearly but not completely', 'The work is almost done.', '这项工作差不多完成了。', '[{"w":"well","def":"well: 相关的动作或关系词","vs":"与 almost 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"well\" / \"almost\" 的替换练习"},{"w":"enough","def":"enough: 可帮助扩展句型的基础词","vs":"与 almost 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"enough\" / \"almost\" 的替换练习"},{"w":"even","def":"even: 同一组 Basic English 操作词","vs":"与 almost 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"even\" / \"almost\" 的替换练习"}]');
